CustomField.formula:
if(leaseworks__Projection_Status__c == "Error",
IMAGE(
    "/resource/" + $Setup.leaseworks__LeaseWorksSettings__c.leaseworks__Package_Prefix__c + "RedeliveryStatusImages/Red.png",
    "Error",
    18,
    18
  ),

if(
leaseworks__Projection_Status__c == "Warning",
IMAGE(
        "/resource/" + $Setup.leaseworks__LeaseWorksSettings__c.leaseworks__Package_Prefix__c + "RedeliveryStatusImages/Orange.png",
        "Warning",
        18,
        18
      ),

if(
leaseworks__Projection_Status__c == "Complete",

IMAGE(
      "/resource/" + $Setup.leaseworks__LeaseWorksSettings__c.leaseworks__Package_Prefix__c + "RedeliveryStatusImages/Green.png",
      "Complete",
      18,
      18
    ),

if(
AND(leaseworks__Projection_Status__c == "", leaseworks__Event_Type__c =='LLP Replacement'), 
   'LLP',
if(
leaseworks__Projection_Status__c == "",
"",

if(
 OR(ISBLANK(leaseworks__Maintenance_Program_Event__c) , ISNULL(leaseworks__Maintenance_Program_Event__c)) , '' , 'LLP'
))))))
